144	                            self.face
145	                                .state
146	                                .primitives
147	                                .send_response_final(&mut ResponseFinal {
148	                                    rid: request_id,
149	                                    ext_qos: qos,
150	                                    ext_tstamp: None,
151	                                });
152	                            return Ok(());
153	                        }
154	                    }
