158	                            // request was blocked by an interceptor, we need to send declare final to avoid timeout error
159	                            self.face.state.primitives.send_declare(RoutingContext::new(
160	                                &mut Declare {
161	                                    interest_id: Some(interest_id),
162	                                    ext_qos: ext::QoSType::DECLARE,
163	                                    ext_tstamp: None,
164	                                    ext_nodeid: ext::NodeIdType::DEFAULT,
